from fastapi import FastAPI, BackgroundTasks
from pydantic import BaseModel
import asyncio, anthropic, uuid

app = FastAPI()
client = anthropic.AsyncAnthropic()
jobs: dict = {}

class EvalRequest(BaseModel):
    prompts: list[str]
    model: str = "claude-opus-4-5"

async def run_batch_eval(job_id: str, prompts: list[str], model: str):
    """Runs all prompts concurrently, records results in jobs dict."""
    jobs[job_id]["status"] = "running"
    try:
        async def eval_one(prompt: str) -> dict:
            msg = await client.messages.create(
                model=model, max_tokens=256,
                messages=[{"role": "user", "content": prompt}]
            )
            return {"prompt": prompt, "response": msg.content[0].text}

        # Run all prompts in parallel
        results = await asyncio.gather(*[eval_one(p) for p in prompts])
        jobs[job_id].update({"status": "completed", "results": results})
    except Exception as e:
        jobs[job_id].update({"status": "failed", "error": str(e)})

@app.post("/api/v1/evals", status_code=202)
async def create_eval(body: EvalRequest, background_tasks: BackgroundTasks):
    job_id = str(uuid.uuid4())
    jobs[job_id] = {"id": job_id, "status": "pending", "results": None}
    background_tasks.add_task(run_batch_eval, job_id, body.prompts, body.model)
    return {"job_id": job_id, "poll_url": f"/api/v1/evals/{job_id}"}

@app.get("/api/v1/evals/{job_id}")
async def get_eval(job_id: str):
    if job_id not in jobs:
        from fastapi import HTTPException
        raise HTTPException(status_code=404, detail="Job not found")
    return jobs[job_id]
